from uuid import uuid4import httpxfrom a2a.client import A2ACardResolver, A2AClientfrom a2a.types import MessageSendParams, SendMessageRequestasync def main():        agents_base_urls = ['http://localhost:9999']        httpx_client = httpx.AsyncClient(timeout=10)    selected_agent_card = None    all_agents_cards = []    for agent_base_url in agents_base_urls:        resolver = A2ACardResolver(httpx_client=httpx_client,                                   base_url=agent_base_url)        try:            agent_card = (await resolver.get_agent_card())            all_agents_cards.append(agent_card)        except Exception as e:            raise RuntimeError('Failed to fetch the public agent card. Cannot continue.') from e    if len(all_agents_cards) == 0:        raise RuntimeError('Failed to find any agent card.')    prompt = 'What is the weather in Cairo?'    selected_agent_card = all_agents_cards[0]    client = A2AClient(httpx_client=httpx_client,                        agent_card=selected_agent_card)    send_message_payload = {        'message': {            'role': 'user',            'parts': [{'kind': 'text', 'text': prompt}],            'messageId': uuid4().hex,        },    }    request = SendMessageRequest(id=str(uuid4()),                                      params=MessageSendParams(**send_message_payload))    response = await client.send_message(request)    print(f"Generated Response: {response}")if __name__ == '__main__':    import asyncio    asyncio.run(main())